def evaluate(expr: str) -> float:
    tokens = []
    i = 0
    n = len(expr)
    while i < n:
        c = expr[i]
        if c.isspace():
            i += 1
            continue
        if c.isdigit() or c == '.':
            j = i
            dot = False
            while j < n and (expr[j].isdigit() or expr[j] == '.'):
                if expr[j] == '.':
                    if dot:
                        raise ValueError("invalid number literal")
                    dot = True
                j += 1
            lit = expr[i:j]
            if lit == '.':
                raise ValueError("invalid number literal")
            tokens.append(('num', float(lit)))
            i = j
            continue
        if c == '*' and i + 1 < n and expr[i + 1] == '*':
            tokens.append(('op', '**'))
            i += 2
            continue
        if c in '+-*/()':
            tokens.append(('op', c))
            i += 1
            continue
        raise ValueError("illegal character: %r" % c)

    if not tokens:
        raise ValueError("empty expression")

    pos = [0]

    def peek():
        if pos[0] < len(tokens):
            return tokens[pos[0]]
        return None

    def advance():
        tok = tokens[pos[0]]
        pos[0] += 1
        return tok

    def parse_expr():
        value = parse_term()
        while True:
            tok = peek()
            if tok and tok[0] == 'op' and tok[1] in ('+', '-'):
                advance()
                rhs = parse_term()
                value = value + rhs if tok[1] == '+' else value - rhs
            else:
                return value

    def parse_term():
        value = parse_factor()
        while True:
            tok = peek()
            if tok and tok[0] == 'op' and tok[1] in ('*', '/'):
                advance()
                rhs = parse_factor()
                value = value * rhs if tok[1] == '*' else value / rhs
            else:
                return value

    def parse_factor():
        tok = peek()
        if tok and tok[0] == 'op' and tok[1] == '-':
            advance()
            return -parse_factor()
        if tok and tok[0] == 'op' and tok[1] == '+':
            advance()
            return +parse_factor()
        return parse_power()

    def parse_power():
        base = parse_atom()
        tok = peek()
        if tok and tok[0] == 'op' and tok[1] == '**':
            advance()
            exponent = parse_factor()
            return base ** exponent
        return base

    def parse_atom():
        tok = peek()
        if tok is None:
            raise ValueError("unexpected end of expression")
        if tok[0] == 'num':
            advance()
            return tok[1]
        if tok[0] == 'op' and tok[1] == '(':
            advance()
            value = parse_expr()
            closing = peek()
            if closing is None or closing[1] != ')':
                raise ValueError("unbalanced parentheses")
            advance()
            return value
        raise ValueError("unexpected token: %r" % (tok[1],))

    result = parse_expr()
    if pos[0] != len(tokens):
        raise ValueError("unexpected trailing input")
    return float(result)
